    scanf("%d", &n);

    // Dynamically allocate memory for the table
    table = (int*)malloc(n * sizeof(int));
    if (table == NULL) {
        printf("Memory allocation failed!\n");
        return 1;
    }

    // Collect input from the user
    printf("Enter the elements of the table:\n");
    for (i = 0; i < n; i++) {
        printf("Element %d: ", i + 1);
        scanf("%d", &table[i]);
    }

    // Display the table
    printf("\nSequence Table:\n");
    for (i = 0; i < n; i++) {
        printf("%d ", table[i]);
    }
    printf("\n");

    // Free the allocated memory
    free(table);

    return 0;
}
```

